INSERT INTO `faqs` (`id`, `question`, `answer`, `category`, `display_in_home`, `created_at`, `updated_at`) VALUES
(1, 'How can I update my billing details?', 'You can update your billing information from your account settings under the billing section.', 'Billing', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(2, 'Why was I charged twice?', 'Double charges may happen due to network issues. Please contact support for a refund if applicable.', 'Billing', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(3, 'How do I cancel my subscription?', 'You can cancel your subscription anytime from your dashboard under subscription settings.', 'Subscription', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(4, 'Will I get a refund after cancelling subscription?', 'Refunds depend on the plan terms. Please check our refund policy for details.', 'Subscription', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(5, 'Where can I find help articles?', 'You can visit our Help Center section from the main menu for detailed guides.', 'Help Center', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(6, 'How can I contact customer support?', 'You can contact support via live chat or email from the Help Center page.', 'Help Center', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(7, 'How does this platform work?', 'You can browse guides, select a service, and book sessions directly online.', 'How it Works', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(8, 'How do I book a session with a guide?', 'Select a guide, choose your preferred time slot, and complete the payment to confirm.', 'How it Works', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(9, 'What is a horoscope reading?', 'Horoscope reading is based on your zodiac sign and planetary positions.', 'Horoscope', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(10, 'How accurate are horoscope predictions?', 'Accuracy depends on various factors, but our experts aim to provide reliable insights.', 'Horoscope', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(11, 'What is tarot reading?', 'Tarot reading uses cards to provide insights into your life and future.', 'Tarot', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(12, 'Do I need prior experience for tarot sessions?', 'No, our guides will explain everything during the session.', 'Tarot', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(13, 'How do I choose the right guide?', 'You can check guide profiles, ratings, and reviews before booking.', 'Guide', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(14, 'What qualifications do your guides have?', 'Our guides are experienced professionals with verified backgrounds.', 'Guide', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(15, 'Can I switch my guide after booking?', 'Yes, you can switch before the session starts, subject to availability.', 'Guide', 0, '2026-03-19 20:49:28', '2026-03-19 15:19:28'),
(16, 'How do I download my invoice?', 'Invoices can be downloaded from the billing section in your account dashboard.', 'Billing', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:40'),
(17, 'Is GST included in pricing?', 'Yes, all applicable taxes are included in the final billing amount.', 'Billing', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:44'),
(18, 'Can I upgrade my subscription plan?', 'Yes, you can upgrade anytime from your subscription settings.', 'Subscription', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:45'),
(19, 'Do subscriptions renew automatically?', 'Yes, subscriptions are auto-renewed unless cancelled manually.', 'Subscription', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:46'),
(20, 'Where can I check my subscription status?', 'You can view your current subscription status in your profile dashboard.', 'Subscription', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(21, 'How do I reset my password?', 'Go to login page and click on \"Forgot Password\" to reset your password.', 'Help Center', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:46'),
(22, 'Why am I not receiving emails?', 'Please check your spam folder or ensure your email is entered correctly.', 'Help Center', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:47'),
(23, 'Can I change my registered email?', 'Yes, you can update your email from account settings.', 'Help Center', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(24, 'What happens after booking a session?', 'You will receive confirmation and session details via email or dashboard.', 'How it Works', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:48'),
(25, 'Can I book multiple sessions at once?', 'Yes, you can book multiple sessions depending on guide availability.', 'How it Works', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:49'),
(26, 'Do I need to create an account to book?', 'Yes, account registration is required before booking.', 'How it Works', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(27, 'How often should I check my horoscope?', 'You can check daily, weekly, or monthly horoscopes based on your preference.', 'Horoscope', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:51'),
(28, 'Is horoscope based on date of birth?', 'Yes, horoscope predictions are primarily based on your birth date and time.', 'Horoscope', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:52'),
(29, 'Can horoscope predict exact future?', 'Horoscope provides guidance, not exact future predictions.', 'Horoscope', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(30, 'How many tarot cards are used in a session?', 'Typically, 3 to 10 cards are used depending on the spread.', 'Tarot', 1, '2026-03-19 20:49:50', '2026-03-19 10:00:53'),
(31, 'Is tarot reading safe?', 'Yes, tarot reading is completely safe and used for guidance purposes.', 'Tarot', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(32, 'Can tarot predict relationships?', 'Yes, tarot can provide insights into relationships and emotions.', 'Tarot', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(33, 'Can I see reviews of guides?', 'Yes, each guide profile displays ratings and customer reviews.', 'Guide', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(34, 'Are guides available 24/7?', 'Some guides are available 24/7, depending on their schedule.', 'Guide', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50'),
(35, 'Can I rate a guide after session?', 'Yes, you can rate and review guides after completing a session.', 'Guide', 0, '2026-03-19 20:49:50', '2026-03-19 15:19:50');

