--
-- Table structure for table `horoscope_monthly`
--

CREATE TABLE `horoscope_monthly` (
  `id` int(11) NOT NULL,
  `sign_id` int(11) DEFAULT NULL,
  `month` int(11) DEFAULT NULL,
  `year` int(11) DEFAULT NULL,
  `prediction` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `horoscope_monthly`
--

INSERT INTO `horoscope_monthly` (`id`, `sign_id`, `month`, `year`, `prediction`, `created_at`, `updated_at`) VALUES
(1, 1, 3, 2026, '[\"March 2026 asks you to look at your life with honest eyes, Aries. With the Sun, Mercury, and Pluto moving through your sign, you feel more aware of your worth. You know you are capable of more, and you are not ready to settle for less. This month pushes you to think about what kind of daily life truly makes you happy. You may feel a strong wish to take control and shape your future in a bold way.\",\"At the beginning of the month, Mercury\'s influence is strong in your sign. Your mind feels sharp, and you want to talk things through. You may feel a deep need to gather your family or close friends and spend real time with them. Conversations are not just small talk now. They help you understand yourself better. Someone close to you may say something that opens your eyes in an important way.\",\"Instead of reacting quickly, you choose to listen carefully. That is not always easy for you, but this time you understand the value of it. You may realize that some of your habits or reactions need to change. These talks can help you see your blind spots. Because Mercury is active in your first house, your personal growth depends on honest communication. What you hear now can guide your next steps wisely.\",\"There is also a warm feeling around your relationships early this month. You notice how lucky you are to have people who truly care about you. You understand that bonds need attention if they are to stay strong. You may feel moved to show appreciation through kind words or a thoughtful action. A simple gesture from you can mean a lot to someone. Giving love freely strengthens your own heart too.\",\"The Full Moon this month brings clarity. It helps you focus on goals that really matter to you. Lately, you may have been busy handling duties and meeting other people\'s expectations. Now you feel ready to return to your own dreams. This lunar phase lights up your desire to live in a way that matches your true values. Being honest with yourself becomes very important.\",\"As the month moves forward, Pluto\'s presence in your sign grows stronger. The second half of March is more intense. You start thinking seriously about changes you want to make. These are not small adjustments. They may involve your career, your daily habits, or even your closest relationships. You do not want to change everything at once, but you know something must shift.\",\"The good news is that you are not alone in this process. The people who care about you can see your courage. They may not fully understand every decision at first, but they respect your honesty. Some friends may even offer helpful advice or support. Their encouragement gives you confidence. When you combine your strong will with wise guidance, you make better choices.\",\"Love can feel a bit tense in the second half of the month. If you are in a relationship, your need for change might confuse your partner. You may want more freedom or a new direction. It is important to speak gently and explain your feelings clearly. If you are single, Pluto helps you look at your patterns in love. You may question old beliefs and become more open.\",\"The New Moon later in the month turns your attention inward. You may feel more sensitive and thoughtful. This is a good time to sit quietly and reflect on your deeper feelings. Pay attention to your dreams and inner voice. Insights that come now can guide your future decisions. This New Moon supports emotional healing and helps you feel calmer about what lies ahead.\",\"At work, your ambition is strong, especially toward the end of March. Mars and Uranus push you to act boldly. You are not afraid to stand out or follow your own path. Some coworkers may not understand your drive, but you do not let that stop you. If you have contracts to finalize or important meetings, you handle them with confidence. Financial matters may require patience, even if progress is promised. Overall, March 2026 is a turning point. By listening, reflecting, and acting with courage, you move closer to the life you truly want.\"]', '2026-03-19 00:00:05', '2026-03-19 00:00:05'),
(2, 2, 3, 2026, '[\"Taurus, March 2026 brings a steady but powerful push forward in your life. The Sun, Mars, and Jupiter are all working in your favor, giving you strong energy and a clear wish to improve things. You feel ready to act, but you also want your choices to be wise and long lasting. That balance between action and patience is your biggest strength this month. Both your career and love life show signs of growth if you stay calm and focused.\",\"At the beginning of the month, you feel a strong need to prove something to yourself. You have been thinking about certain changes for a while. Some parts of your daily routine no longer feel exciting. Under the Sun\'s influence, you want more joy and meaning. You are not trying to turn your life upside down, but you do want small improvements that make a big difference over time.\",\"Even though you have clear goals in mind, you usually refuse to rush. That is very true now. Jupiter supports careful planning, especially in long-term matters. You understand that real success takes time. Instead of acting on impulse, you think things through. This patient attitude helps you avoid mistakes. You are building something solid, and you would rather move slowly than regret a quick decision later.\",\"Your career and financial matters take up more space in your thoughts during the first half of the month. Work is not just about paying bills for you. It is also about pride and personal growth. Mars gives you extra drive to improve your position. You may feel ready to ask for more responsibility or take steps toward a new direction. Just make sure your actions match your true priorities.\",\"The Full Moon early in the month stirs up old emotions. It shines a light on memories that you may have pushed aside. This lunar phase happens in a sensitive area of your chart, asking you to release past regrets. You might feel slightly emotional or thoughtful for a few days. Do not ignore these feelings. Accepting what is over allows you to move ahead without carrying extra weight.\",\"As the month moves toward the middle, you begin to see results from your efforts. Jupiter\'s transit through your sign brings quiet luck. Doors can open in work, and money matters slowly improve. You feel more confident about your future. Instead of doubting yourself, you trust your skills. This positive mindset attracts helpful people and good opportunities. Your steady effort is finally being noticed.\",\"Your love life also gains warmth during the second half of March. If you are in a relationship, your partner shows support and affection. You may talk about future plans or shared goals. Venus encourages gentle communication and romance. If you are single, you appear more confident and relaxed. Someone could be drawn to your calm charm. A meeting through friends or social events is possible.\",\"Mid-month, you may notice how important teamwork is at work. Neptune can sometimes make you believe you already know everything. However, Saturn reminds you that growth comes from learning. Accepting advice from others improves your reputation. When you cooperate instead of trying to handle everything alone, progress becomes easier. This change in attitude can open a surprising professional opportunity.\",\"The New Moon toward the end of the month invites you to slow down. After weeks of effort, your body and mind need rest. This lunar phase supports reflection and planning rather than action. Use this time to recharge and rethink your long-term goals. You do not need to fight every battle immediately. Keeping your strength for the right moment is wiser than using it all at once.\",\"Financially, the end of March feels reassuring. You may not feel rich, but you feel stable. Jupiter continues to support growth in income over time. A smart decision made earlier could now show benefits. Instead of spending carelessly, you think about security. This careful attitude keeps you comfortable. You are learning that steady progress is better than risky moves.\",\"Overall, March 2026 is a month of steady advancement for you. The Sun fuels your confidence, Mars gives you courage, and Jupiter rewards your patience. You are learning to mix action with careful thought. By letting go of the past and trusting your plans, you create space for lasting success. If you stay true to your values and remain open to advice, this month leaves you feeling stronger and hopeful about what lies ahead.\"]', '2026-03-19 00:00:05', '2026-03-19 00:00:05'),
(3, 3, 3, 2026, '[\"Gemini, March brings a thoughtful and meaningful mood for you. With the Moon, Mercury, and Saturn strongly active in your chart, you start to think more seriously about what you truly want.\",\"Lately, you may have been busy meeting other people\'s needs or just going through your routine. Now you feel a quiet push inside to refocus on yourself. You want to understand your deeper desires so you can build a life that feels honest and steady.\",\"At the beginning of the month, the Moon encourages you to look inward instead of rushing forward. Even if your current situation looks fine from the outside, you can sense that something is missing. Old memories or past experiences may come back to your mind. Some of them might still affect your confidence. Instead of ignoring them, you are ready to face them. This reflection helps you understand why you react the way you do.\",\"The first two weeks are more about thinking than acting. Saturn\'s influence asks you to slow down and be realistic. You do not need to make big life decisions right now. Instead, take time to study your own patterns. Ask yourself what truly matters. What values guide you? What kind of future feels right? Being honest with yourself is not always easy, but it gives you strength and direction.\",\"The Full Moon early in the month highlights your emotions. You may feel extra sensitive, especially in close relationships. If you are in a relationship, you might want reassurance from your partner. Sharing your worries openly can actually bring you closer. If you are single, you may feel ready to lower your guard a little. Someone around you could notice your honesty and kindness. Take things slowly and allow trust to grow naturally.\",\"Mid-month, Mercury becomes more supportive, especially in your social and professional life. Communication flows more easily. Conversations with friends or family help you see your situation clearly. Someone\'s advice may guide you toward a choice that feels more aligned with who you are becoming. At work, your ideas stand out. If you speak up and show what you can do, others will notice your effort.\",\"Around the middle of March, you may also realize that emotions cannot be separated from your job. The Moon\'s influence shows you that feeling respected and valued at work truly matters to you. You might try to improve the atmosphere around you by being more open and supportive. Small changes in how you communicate can slowly create a healthier environment.\",\"As the second half of the month unfolds, your focus shifts more strongly toward love and friendship. Venus and Mercury together help you express affection in simple but meaningful ways. If you are in a committed relationship, you understand that love needs attention. A small gesture, a kind word, or quality time can make a big difference. Your partner appreciates your effort to keep the bond alive.\",\"If you are looking for love, this period feels promising. Your natural charm is strong, but this month your sensitivity is what truly attracts others. You are not trying too hard; you are simply being yourself. That honesty creates connection. At the same time, you are careful not to lose your independence. You want someone who respects your freedom and understands your curious nature.\",\"The New Moon later in the month brings a softer and warmer energy. You feel a stronger need to share your life with others. Emotional exchange becomes important. You may plan simple gatherings, meaningful talks, or quiet moments with someone close. These shared experiences remind you that happiness grows when it is not kept only for yourself.\",\"Financially, Mars gives you steady motivation. You are not careless with money, and your past efforts have created a stable base. This month, you continue working hard without feeling forced. You understand that consistency builds security. Professionally, opportunities can appear if you stay confident and present your skills clearly.\",\"By the end of March, you feel lighter and more hopeful. The reflection you did earlier in the month now makes sense. You see new possibilities forming in front of you. Instead of rushing, you move with patience and clarity. Your good mood spreads to others, and in return, you receive support when you need it. March helps you grow from the inside out, Gemini, and that inner change shapes your future in a steady way.\"]', '2026-03-19 00:00:05', '2026-03-19 00:00:05'),
(4, 4, 3, 2026, '[\"Cancer, March brings a strong mix of feelings and determination for you. With the Moon, Mars, and Saturn influencing your chart, you may feel more sensitive than usual, yet also braver inside. Your emotions will not confuse you; instead, they will guide you. You start to understand what you truly need, not what others expect from you. This month helps you see which parts of your daily life feel right and which parts quietly need change or improvement.\",\"At the beginning of the month, a small inner voice grows louder. Even if life looks stable on the outside, you may feel that something needs to shift. It could be about your job, your habits, or your personal goals. Mars gives you courage, and the Moon sharpens your intuition. You may surprise people close to you by speaking clearly about what you want. Not everyone will understand right away, but they will respect your honesty and strength.\",\"During the first two weeks, change is strongly on your mind. You might feel ready to make an important decision that shapes your future. This does not mean you are unhappy; it simply means you want more meaning and comfort in your life. Saturn reminds you that real progress takes time. So even if you feel excited, you will not act blindly. You will think carefully before taking any big step, especially in love or career matters.\",\"Your love life becomes a major focus now. If you are in a relationship, you may feel that things have become too predictable. You still care deeply, but you want more warmth, fun, or shared experiences. Instead of staying silent, you choose to talk openly. Mercury supports communication in your chart, helping you express your needs gently. Honest conversations can bring you closer. If you are single, this month may open the door to meeting someone interesting.\",\"Around the time of the Full Moon, emotions rise to the surface. You cannot ignore how you truly feel. This lunar phase pushes you to accept your desires without guilt. If something feels wrong, you admit it. If something feels right, you allow yourself to enjoy it fully. This moment helps you understand your path more clearly. When you are honest with yourself, your decisions become easier, and your heart feels lighter.\",\"Financially, you receive encouraging signals. The Sun highlights your ability to manage resources wisely. You may hear positive news related to income, savings, or an investment. Even if your spending habits have not always been consistent, you have strong instincts about money. This month helps you use those instincts better. Instead of acting on impulse, you think about long-term stability. A calm approach improves your confidence and reduces stress about finances.\",\"In your work life, ambition quietly grows. You may feel ready for new responsibilities or a fresh challenge. However, Saturn advises patience. If you rush or show frustration openly, it could slow your progress. Neptune\'s influence suggests that you should plan carefully before speaking or acting. If you are searching for a job, your determination increases. You feel more focused and less afraid of rejection. A steady effort brings you closer to a breakthrough.\",\"As the second half of the month begins, your energy softens. You no longer feel pressure to act immediately. Instead, you take time to reflect. This calmer phase allows you to organize your thoughts and adjust your plans. Advice from family or trusted friends becomes valuable. They may point out things you did not see. Listening does not weaken you; it strengthens your decisions. You begin separating temporary wishes from deeper, lasting needs.\",\"With the New Moon influencing your chart later in the month, you feel curious and ready for small experiments. You might try a new hobby, visit a new place, or change part of your routine. Stepping outside familiar patterns feels refreshing. Routine has given you safety, but now you want gentle excitement too. These small changes remind you that growth does not always require dramatic action. Sometimes, small shifts bring the biggest happiness.\",\"By the end of March, you feel calmer and more hopeful. Spending time with family and close friends brings comfort and warmth. You see how far you have come, and you trust your own strength more than before. You understand that lasting change happens step by step. Instead of rushing, you choose patience. March teaches you that listening to your heart, while thinking wisely, leads you toward a more balanced and fulfilling future.\"]', '2026-03-19 00:00:05', '2026-03-19 00:00:05'),
(5, 5, 3, 2026, '[\"Leo, March 2026 asks you to slow down and look within instead of rushing ahead. Even though you usually like clear action and quick results, this month feels quieter and more thoughtful. The meeting of the Moon, Saturn, and Neptune in your sky turns your focus toward feelings, faith, and deeper questions. You may not feel pushed to make bold moves, but you will strongly feel the need to understand yourself better and rethink certain life choices carefully.\",\"During the first two weeks, the Moon has a strong effect on you. Your emotions rise to the surface, and you become more aware of what truly makes you happy or uncomfortable. Small daily situations may suddenly feel meaningful. You start asking yourself if your routine still satisfies you. Instead of ignoring your feelings, you try to understand them. This emotional honesty helps you grow. By listening closely to your heart, you begin to see where small changes are needed.\",\"You may also notice old fears or doubts appearing again. Saturn\'s presence reminds you of responsibilities, past lessons, and limits. At first, this can feel heavy, like you are carrying extra weight. But this influence is not here to block you. It is here to help you build something solid. When you face your weaknesses honestly, you gain strength. You understand that real confidence does not come from pretending everything is perfect, but from knowing yourself fully.\",\"Neptune adds a spiritual tone to March. You may think more about your purpose and what truly matters in your life. Questions about your career path, personal values, and long-term dreams become important. You want your life to reflect who you truly are, not just what others expect. The Full Moon early in the month highlights this need. It brings clarity about the place you want to occupy in the world and the role you wish to play.\",\"In love, this month feels thoughtful rather than dramatic. If you are in a long-term relationship, your partner becomes your safe space. Even if you feel uncertain about other areas of life, you know you are not alone. Honest talks help you feel calmer. You may share your worries or dreams more openly. If you are single, romance may not be the main focus now. Instead, you work on understanding your emotional patterns and what you truly want.\",\"Mid-month, the New Moon shifts your attention toward connection and shared experiences. You feel a stronger wish to spend quality time with people who matter to you. This is a good period to strengthen friendships and family ties. You may meet new people through social events or group activities. Even simple conversations can inspire you. Building strong bonds now helps you feel supported while you continue working on your inner growth and long-term plans.\",\"Financially, Saturn makes you careful. You prefer safety over risk. Instead of spending freely, you think about stability and future needs. You might review your budget or reconsider certain investments. Old worries about money could return, but they push you to act wisely. Planning carefully gives you peace of mind. By choosing security over impulse, you protect yourself from unnecessary stress and build a stronger foundation for the months ahead.\",\"Work matters may feel intense toward the end of the month. Mars creates activity in your professional life, possibly bringing meetings, discussions, or even the idea of a transfer or change of position. At first, this can make you uncomfortable. You do not always like sudden changes to your routine. However, this transit asks you to stay open. Even if you feel unsure, you have time to think before making any final decision.\",\"Emotionally, one particular day may test your patience. Under a strong Mars aspect, you could defend your opinions too strongly. Others may see your frustration more clearly than you expect.\",\"It will be important to speak calmly and listen carefully. Arguments can be avoided if you slow down and choose your words wisely. Remember that being right is not always as important as keeping peace and mutual respect in your relationships.\",\"As spring energy builds toward the end of March, your mood slowly lifts. You begin to see possibilities instead of limits. Even if not everything is settled yet, you feel hopeful. You understand that growth takes time, especially when Saturn is involved. Small daily progress matters more than dramatic changes. By the end of the month, you feel more stable, more honest with yourself, and more ready to follow a path that truly fits who you are.\"]', '2026-03-19 00:00:05', '2026-03-19 00:00:05'),
(6, 6, 3, 2026, '[\"Virgo, March 2026 may not be the calm month you expected, but it can turn out to be meaningful in many ways. With the Moon linking up with Uranus in your chart, sudden changes or surprises may shake your routine. At first, this might feel uncomfortable because you like order and stability. Still, deep inside, you know something in your daily life needs to shift. This month pushes you to look honestly at what is working and what is not anymore.\",\"At the beginning of the month, you may feel more emotional than usual. The Moon\'s influence can make your reactions stronger, especially if you already feel restless. Uranus adds a need for freedom and change. You might question habits, work patterns, or even certain relationships. Instead of ignoring these feelings, take them seriously. You are not someone who stays satisfied with \\u201cgood enough.\\u201d You want steady progress. That means accepting that change, even if sudden, can move you closer to the life you want.\",\"Money and security will be on your mind in the first two weeks. You are careful with finances by nature, and this month you may review your accounts, savings, or spending habits. You are not in trouble, but you sense that things could improve. This is a good time to plan smarter rather than spend carelessly. A strong Mercury transit helps you think clearly and make practical choices. Talking with a trusted person about money could also give you useful ideas.\",\"The Full Moon early in the month helps you slow down and find balance. You need peace and harmony to feel stable, and this lunar phase reminds you of that. Instead of reacting quickly to every problem, step back. Give yourself quiet time. When you pause and reflect, you see the bigger picture. This moment can help you decide which goals truly matter and which worries are not worth your energy anymore.\",\"In your work life, Mars brings strong drive but also impatience. You may feel an urge to push forward or prove yourself. That energy is powerful, but if you let it turn into anger or sharp words, it could create tension with coworkers or bosses. Try to channel Mars into focused action instead of conflict. Think long term. A small win now is not worth damaging your reputation later. Calm strength will serve you better.\",\"Mid-month, Mercury supports open conversations. If you have been holding back your feelings, this is the time to speak honestly but kindly. Loved ones are more willing to listen than you think. You do not have to solve everything alone. Sharing your thoughts can reduce confusion and stop misunderstandings before they grow. If you feel uncertain, asking for advice will not make you weak. It will help you make wiser decisions.\",\"Your love life may feel a bit too routine lately. With Pluto influencing your emotional zone, you may crave deeper feelings and stronger connection. If you are in a relationship, you might want to change old patterns. Try to express your needs clearly instead of acting suddenly. If you are single, an unexpected meeting is possible, especially when you allow yourself to step outside your normal circle. Keep your heart open but steady.\",\"Social connections also become important as the month moves forward. You may feel a strong desire to reconnect with friends or family members. A simple gathering or outing can lift your mood more than you expect. As spring energy builds, warmth from others reminds you that success is not only about work or achievements. Relationships give you strength and help you grow. Make time for laughter and shared moments.\",\"The New Moon later in March turns your focus inward. This phase increases your intuition and makes you think about your true values. You may ask yourself what kind of future you really want. Instead of rushing into big actions, use this time to set quiet intentions. When you understand your deeper motivations, your next steps become clearer. Emotional balance returns when you listen to your inner voice.\",\"Overall, March teaches you patience. Change is coming, but it does not need to happen all at once. The mix of Uranus, the Moon, Mercury, Mars, and Pluto brings strong feelings and strong ideas. If you react too quickly, you may regret it. If you think carefully and seek support, you can shape these changes in your favor. Trust that steady effort and calm thinking will lead you exactly where you need to be.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06'),
(7, 7, 3, 2026, '[\"Libra, March 2026 is for you. This month feels like a fresh wind moving through your life. You may notice that your usual routine no longer feels exciting. A part of you wants something different. With strong transits from Mars, Saturn, and Uranus affecting your chart, change is on your mind. You are thinking about growth and new plans. Even if you like safety, you now feel ready to test new ideas.\",\"At the beginning of the month, Mars gives you energy and courage. You feel more confident about stepping outside your comfort zone. If you have been bored with daily tasks, you will want to try something new. Mars forms bold aspects that push you to act instead of just think. You may speak up more, take initiative at work, or finally start a plan you kept delaying. Your drive is stronger now.\",\"Uranus adds surprise to your days. You might suddenly change your opinion about something important. New people or ideas can enter your life without warning. As a Libra, you enjoy balance, but you also need inspiration. This month reminds you that growth happens when you allow change. Conversations with different types of people help you see problems from new angles. This can bring smart solutions to old issues.\",\"In love, passion increases under Mars. If you are in a relationship, you may feel closer to your partner. Physical attraction and warm moments grow stronger. It is a good time to talk openly and plan something fun together. If you are single, meeting someone new is possible, especially if you try new places or activities. Love may appear when you least expect it, so stay open to chances.\",\"The Full Moon this month shines light on your inner world. You start thinking deeply about your long-term goals and the role you want to play in life. Feelings you ignored may rise to the surface. This can feel intense, but it is helpful. The Moon helps you see what truly matters. Even if results do not appear right away, your thoughts become clearer and your plans improve.\",\"As the month continues, Saturn becomes more noticeable in your chart. Saturn asks you to slow down and think carefully. While Mars pushes for action, Saturn wants responsibility. You may feel unsure about big decisions. One part of you wants fast change, and another part wants security. This mixed feeling is normal. Take your time before making major moves. Careful steps now will protect you later.\",\"Mid-month, you may prefer quiet time. Being alone helps you sort out your thoughts. Instead of rushing forward, you think about risks and rewards. Mercury\'s influence supports planning and honest talks. If you feel fear about the unknown, do not judge yourself. Change can be exciting but also scary. Trust that patience is not weakness. It simply means you want to make wise choices.\",\"The New Moon brings focus to family and close friends. You feel the need to connect with people who care about you. Spending time at home or sharing simple moments brings comfort. Even if work feels demanding, your heart feels lighter when you talk with loved ones. Supporting others also helps you feel valued. Strong bonds remind you that success means more when shared.\",\"Toward the end of the month, your social life becomes more active. Invitations, group talks, or helpful contacts may appear. The Sun supports your confidence, especially in career matters. Professional growth can come through networking. A useful conversation may open a door. Stay friendly and present. Your natural charm works well now. Being cooperative helps you move closer to your goals.\",\"Money matters look steady. You are usually careful with spending, and this habit protects you now. There is no need for risky choices. Stability is your strength this month. At work, you may face small challenges, but the Sun\'s support gives you motivation. If you are searching for a job, keep trying. Even if rewards are slow, you are building progress.\",\"By the end of March, you see that a balance between change and safety is possible. Mars and Uranus give you courage, while Saturn teaches patience. You may not have all the answers yet, but you feel stronger inside. Growth is happening step by step. Trust your instincts and stay calm. With time, your path becomes clearer, and your confidence grows steadily.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06'),
(8, 8, 3, 2026, '[\"Scorpio, March 2026 is a month when your mind feels sharp and your heart feels hopeful. With Mercury, Saturn, and Neptune influencing your chart, you think clearly about what you truly want. You are not confused about your goals anymore. Instead, you see the road ahead and understand that steady effort will take you there. This month rewards patience. If you move step by step and stay calm, you can make real progress.\",\"At the beginning of the month, Neptune\'s energy makes you thoughtful. As the season slowly changes, you take a serious look at your daily life. You notice that many things are working well. You have achieved goals, handled duties, and stayed strong. Still, you also feel that something is missing. Old dreams that you once ignored because of work or family duties return to your mind.\",\"You start asking yourself honest questions. Are you truly happy with your routine? Are you giving time to what excites you? Neptune increases your imagination, while Saturn keeps you realistic. Because of this balance, you do not just dream. You think about how to turn those dreams into practical plans. Some changes may slowly begin this month, especially if you are ready to adjust your priorities.\",\"In love, the first half of March helps you understand your needs better. If you are single, you reflect on past relationships and see what went wrong. You no longer want to repeat the same patterns. Mercury helps you analyze your thoughts clearly. You realize that knowing yourself better will improve your future connections. This self-awareness gives you quiet confidence when meeting someone new.\",\"If you are in a relationship, communication becomes very important. You and your partner may talk about deeper topics, especially about the future. Uranus pushes you to speak honestly about your needs. For a long time, you may have stayed silent just to keep peace. Now you understand that your feelings matter too. Respect grows when both people share openly and listen carefully.\",\"Around the Full Moon, your social life becomes more active. You may receive invitations or simply feel like being around friends. Spending time with people who care about you helps you relax. If you have been stressed, this energy gives relief. If you are single, meeting someone through social gatherings is possible. The connection may feel natural and easy, without pressure.\",\"As the month moves forward, Mercury strengthens your planning skills even more. Your strategic mind becomes your greatest strength. You think about long-term results instead of quick rewards. Saturn supports discipline, so you avoid rushing into decisions. When doubts appear, you are wise enough to ask trusted friends or family for advice. Listening to others does not weaken you; it makes you stronger.\",\"Work becomes a major focus toward the end of the month. Jupiter sends positive aspects that help your efforts stand out. You may feel more comfortable with coworkers and satisfied with your tasks. Still, you question whether your job matches your bigger dreams. You want both stability and meaning. If something feels wrong, you start thinking about practical ways to improve your situation.\",\"Financially, your careful nature helps you. You avoid impulsive spending and think about long-term security. Saturn\'s influence keeps you steady, while Mercury helps you review details before making any investment. This month favors smart planning instead of risky moves. Your patience with money decisions can protect you from future stress. Small but steady steps now can build stronger financial ground later.\",\"The New Moon later in March gives you a fresh start with habits and mindset. You feel ready to remove small distractions that waste your time. This lunar phase supports focusing on what truly matters. You understand that worrying about tiny issues only increases mental pressure. By clearing unnecessary tasks and thoughts, you create space for peace and productivity in your life.\",\"Overall, March 2026 is about thoughtful progress for you, Scorpio. Mercury sharpens your thinking, Neptune reminds you of forgotten dreams, and Saturn teaches patience. The balance between imagination and responsibility helps you grow. You are not rushing or forcing results. Instead, you trust slow and steady effort. If you continue with this calm determination, you can shape a future that feels both secure and deeply satisfying.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06'),
(9, 9, 3, 2026, '[\"Sagittarius, March 2026 brings a lighter and happier mood into your life. With Venus, Jupiter, and Pluto strongly active through key transits, you feel more connected to what truly matters. Your focus turns toward love, joy, and building a daily routine that feels right for you. This month is not about rushing. It is about choosing carefully and making sure your life reflects your real values, not old habits you have outgrown.\",\"During the first part of the month, Venus moves through an important area of your chart, boosting your social life. You feel more open, friendly, and willing to spend time with people you care about. Simple conversations, shared meals, and laughter bring comfort. You may also find yourself giving advice to friends. Your past experiences now become useful tools that help others grow and improve their situations.\",\"If you are single, this Venus influence makes you especially attractive without trying too hard. You seem relaxed, warm, and easy to talk to. If being alone has been bothering you, this is a good time to step outside your comfort zone. Say yes to invitations. Start conversations. A positive chain reaction begins when you believe you deserve love and companionship in your life.\",\"Pluto also plays an important role this month. It pushes you to think deeply about your direction. You may realize that certain parts of your past no longer support your future. Letting go is not always easy, but it is necessary. When you decide to stop repeating old patterns, you free up energy for something better. You are stronger than you think.\",\"Around the time of the Full Moon, emotions become clearer. This lunation highlights your priorities and helps you understand what truly deserves your attention. You may suddenly see a new path opening up. Because you are naturally curious and adventurous, you will feel excited about new possibilities. Try not to limit yourself with fear. Growth begins when you allow yourself to explore new options.\",\"As the second half of the month begins, Jupiter\'s supportive transit increases your confidence and optimism. This is excellent for both personal and professional matters. You feel lucky, but it is more than luck. Your positive attitude attracts helpful situations. At work, you may notice small improvements that lead to bigger results later. Doors begin to open, sometimes in unexpected ways.\",\"In your career, you help create a peaceful environment. If there have been quiet tensions among colleagues, you may step in and smooth things over. However, you are also learning not to let others take advantage of your kindness. Respect matters to you. When you balance diplomacy with firm boundaries, people start seeing you as a reliable and capable leader.\",\"Your love life looks especially promising this month. If you are in a relationship, trust and tenderness grow stronger. You and your partner may talk about starting something new together, like a shared plan or goal. Doing something meaningful as a team strengthens your bond. Small efforts now can create long-lasting stability between you.\",\"If you are still searching for the right person, keep your eyes open during social gatherings or casual outings. Someone interesting could appear when you least expect it. The New Moon encourages you to follow your desires instead of focusing only on responsibilities. You work hard, but you also deserve fun and romance. Balance is important.\",\"There is a particular day this month when Mars gives you extra courage in love matters. You may feel ready to take initiative and speak honestly about your feelings. Your confidence reassures your partner. If single, this energy helps you approach someone new without fear. Being direct works in your favor now, as long as you stay kind.\",\"Financially, you feel tempted to spend more toward the end of the month. Because your mood is good, you may want to treat yourself. While there is nothing wrong with enjoying your money, think carefully before making impulsive purchases. Mercury\'s influence suggests that clear thinking is needed. A smart decision now keeps your future stable and stress free.\",\"Overall, March 2026 feels steady and uplifting for you, Sagittarius. Love, friendships, and career growth all show positive signs. The key lesson is simple: let go of what no longer fits, and move forward with confidence. When your actions match your true beliefs, everything starts to align naturally. This month reminds you that happiness grows when you choose it boldly.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06'),
(10, 10, 3, 2026, '[\"March 2026 brings a strong and active period for you, Capricorn. With powerful transits from Mercury, Mars, and Uranus influencing your chart, you may feel more awake and ready to move forward. This month helps you focus on your long-term goals while also improving your daily life. You are not just dreaming about change\\u2014you are planning it carefully. There is a sense that things are finally shifting in a direction that feels right and meaningful for you.\",\"At the beginning of the month, Mercury plays a big role in your thinking. Your mind feels sharp, and you start to question areas of your life that are not fully satisfying. You may realize that you have accepted certain situations for too long. Instead of feeling upset, you become practical. You calmly look at what needs improvement. This transit supports honest self-talk and smart planning. You begin building a clear plan for what you truly want next.\",\"Work matters take up a lot of space in your thoughts during the first half of the month. If you already have a stable job, you may think about how to improve your position. You might want more responsibility or better teamwork. If you are searching for work, you adjust your strategy. You may update your resume, contact new people, or learn a new skill. Mercury in a helpful aspect supports communication, so speaking up benefits you.\",\"The Full Moon energy early in the month encourages you to slow down for a moment. Even though you are serious about your plans, this lunar phase invites you to try something new. You feel curious and more open to different ideas. If you are single, a surprising meeting or conversation could spark romantic interest. If you are in a relationship, you may want deeper talks. Emotional honesty strengthens your bond.\",\"Financially, there could be a brief moment of worry around the early part of March. With Pluto forming tense aspects to the Moon, you may feel concerned about security. You might double-check your savings or think about future expenses. However, when you look closely, things are more stable than your fears suggest. This is a good time to review budgets and make careful decisions, but avoid acting out of panic.\",\"As the month moves into the second half, Mars increases your energy level. You feel stronger and more determined. Tasks that were delayed suddenly seem easier to handle. You clear old responsibilities and move forward with confidence. This is a powerful period for career progress.\",\"Important people may notice your effort and strategy. Jupiter supports professional growth, so taking initiative can bring positive results and new opportunities.\",\"Your love life also benefits from this surge of energy. If you are in a long-term relationship, you may decide to refresh your routine together. Simple changes, like planning time alone or having honest talks, bring warmth back into the connection. Physical affection and shared laughter help you feel close again. If you are single, you appear more confident and attractive. Others notice your steady and reliable nature.\",\"Your social life becomes more active as well. Even though you are focused on progress, you understand that rest and fun matter. Spending time with friends and family helps you recharge. Trying new activities keeps your mood balanced. Uranus encourages small changes in your routine that bring excitement without causing stress. You do not want to give up your personal time, and this healthy balance supports your overall well-being.\",\"Toward the end of the month, the New Moon invites you to reflect quietly. This is a strong moment for setting personal intentions. You think deeply about your real needs, not just what others expect from you. By listening to your inner voice, you gain clarity about long-term dreams. New Moon energy supports planting seeds for future success. What you decide now can slowly grow over the coming months.\",\"Overall, March 2026 feels constructive and promising for you, Capricorn. Mercury helps you think clearly, Mars gives you drive, Uranus supports smart change, and Jupiter adds growth in career matters. You are realistic but hopeful. You know progress takes time, and you are patient enough to build it step by step. If you manage your energy wisely and trust your practical instincts, this month can move you closer to lasting success in both love and work.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06'),
(11, 11, 3, 2026, '[\"March 2026 brings a steady and hopeful mood for you, Aquarius. Right from the beginning of the month, you may feel ready to improve your habits and treat yourself better. With Venus, Uranus, and Neptune active through key transits in your chart, you think more about balance and long-term happiness. You are not rushing anything now. Instead, you want changes that truly match who you are and what you believe deep inside.\",\"During the first part of the month, Venus supports you through smooth aspects that improve your relationships. You speak with warmth, and people enjoy being around you. At work, this helps you connect with important people who may support your goals. You understand that success is not only about talent but also about teamwork. Your social skills shine, and others see you as someone trustworthy and pleasant to cooperate with.\",\"In your personal life, you crave meaningful conversations and shared moments. Spending time with family or close friends feels refreshing. Their advice may help you see your situation clearly. If something has been bothering you, talking it out makes a difference. You realize that having good allies around you is one of your biggest strengths this month, and you do not take that support for granted at all.\",\"As the season begins to shift, you feel more energetic and open to trying new things. You may want to start a new hobby, change your routine, or focus on better health habits. Mars gives you motivation, but you use it wisely. You step slightly outside your comfort zone without forcing yourself. This fresh energy also improves your mood, making you more playful and open in your daily life.\",\"The full moon early in the month lights up your inner world. It pushes you to be honest with yourself about your feelings and needs. You think about what truly motivates you and what drains your energy. Instead of ignoring your weak points, you calmly accept them and look for ways to improve. This self-awareness helps you feel stronger and more prepared for the future.\",\"In love, this month feels both exciting and comforting. If you are single, your natural charm attracts attention without you trying too hard. You stay relaxed and avoid getting carried away too quickly. A new meeting is possible, especially when you least expect it. If you are in a relationship, you bring more warmth into your bond. Small gestures, kind words, and shared laughter make your connection stronger.\",\"However, towards the end of the month, Uranus may create a moment of emotional distance. You might feel the need to spend time alone and think quietly. If you are partnered, explain this gently so your loved one does not misunderstand. If you are single, you may prefer staying home instead of going out. This short pause helps you sort out your thoughts and understand what you really want.\",\"Financially, the energy looks supportive. Pluto influences your money sector, encouraging growth and confidence. You may feel less guilty about spending on yourself. If you have been too strict with your budget, this month reminds you that balance is important. Treating yourself once in a while is healthy. At the same time, you remain practical and avoid careless decisions. Your choices around money feel steady and well thought out.\",\"In your career, your honesty and enthusiasm stand out. Jupiter forms helpful aspects that allow your work to be noticed by the right people. You may be trusted with larger tasks or leadership roles. You enjoy responsibility when it aligns with your values. Instead of acting out of pressure, you act from confidence. Your calm attitude helps you handle duties smoothly and maintain good relationships with colleagues.\",\"During the second half of March, Neptune encourages you to think deeply about your priorities. You no longer want to follow other people\'s expectations if they do not fit your dreams. You trust your own judgment more than before. If someone doubts your ideas, you stay polite but firm. You understand that your path is unique. Listening to your heart becomes more important than pleasing everyone around you.\",\"Overall, March 2026 feels balanced and meaningful for you. With steady planetary influences guiding your houses of relationships, work, and self-growth, you move forward without rushing.\",\"You have patience, clear thinking, and quiet confidence. There is no need to force outcomes. By trusting your instincts and keeping strong connections around you, you create steady progress that supports both your personal happiness and future success.\"]', '2026-03-19 00:00:06', '2026-03-19 00:00:06');
INSERT INTO `horoscope_monthly` (`id`, `sign_id`, `month`, `year`, `prediction`, `created_at`, `updated_at`) VALUES
(12, 12, 3, 2026, '[\"Pisces, March 2026 opens with strong and supportive energy around you. With Mars, Jupiter, and Neptune moving through important areas of your chart, you feel more alive and ready to act. You want happiness, but you also want progress. You are not just dreaming about a better life; you are thinking about real steps to make it happen. This month, you feel braver and more certain about what you truly want for your future path.\",\"During the first half of the month, Mars pushes you forward. You are filled with courage and determination. If something has been bothering you for a long time, you may finally decide to deal with it. This is not a sudden decision. You have been thinking deeply for months, especially while slower transits worked quietly in the background. Now you feel ready to act. You trust your instincts and refuse to let fear stop you anymore.\",\"Your energy is high, and it shows in everything you do. Whether it is a personal goal, a hobby, or a career plan, you work with passion. People notice your drive. You are not waiting for permission. Instead, you take control of your own direction. This active phase feels natural to you, even if you usually prefer a softer approach. This month, your fire is stronger, and it helps you move forward with confidence.\",\"Love becomes brighter under these influences. If you are in a relationship, your partner may see a more playful and bold side of you. You suggest new activities or deeper talks, and this brings excitement back into your bond. Venus supports romance, while Neptune adds emotional depth. If you are single, your open heart increases your chances of meeting someone interesting. You are more willing to show your true self, and that attracts attention.\",\"A full moon early in the month lights up your social life. You may feel a strong need to connect with friends or family. Conversations become honest and meaningful. You might share personal thoughts you have kept inside. Their advice helps you see your situation from a new angle. This full moon also highlights one of your houses of communication, helping you speak clearly about what matters to you without confusion.\",\"As the month moves forward, Jupiter plays a big role. This planet brings growth and positive results, especially in your career sector. You may feel that you are finally on the right track. If you have been working hard, recognition could come your way. A new project or opportunity might appear, something that better matches your skills and long-term plans. If you are searching for a job, your confidence leaves a strong impression.\",\"Still, when it comes to money, you need to stay careful. Certain aspects between Mars and Uranus can push you to act too quickly with finances. You might feel excited about an idea or investment, but it is important to slow down. Think clearly before making big decisions. Risk-free options are better this month. Mercury\'s influence reminds you to use logic and not just emotion when handling your resources.\",\"Mid-month, a new moon deepens your emotional awareness. You may notice your feelings more clearly. Instead of ignoring them, you choose to understand them. This is helpful for personal growth. Even though you can be practical when needed, you know your emotions guide you in important ways. The new moon supports fresh starts, especially in matters related to self-worth and personal direction. You feel ready to set new intentions.\",\"In your relationship, Mercury may also bring small doubts. If you are committed, you might question certain details about your partner\'s behavior. This does not mean something is wrong, but it shows your mind is active. Honest communication is the key. If you are single, you could feel torn between logic and desire. Someone you have liked for a while may come closer. You must decide if you are ready to follow your heart.\",\"Toward the end of the month, Mars boosts your professional life again. You feel productive and proud of your abilities. If there is a presentation, interview, or important task, you handle it with strength. Your determination helps you stand out. Overall, March 2026 feels powerful for you. With strong transits supporting action, love, and growth, you move through the month with belief in yourself and a clear sense of direction.\"]', '2026-03-19 00:00:07', '2026-03-19 00:00:07');

