INSERT INTO `services` (`id`, `title`, `thumbnail`, `banner_image`, `small_description`, `full_description`, `final_thoughts`, `created_at`, `updated_at`) VALUES
(1, 'Tarot Reading', 'tarot_thumb.jpg', 'tarot_banner.jpg', 'Get insights into your life through tarot cards.', 'Our tarot reading service helps you understand your past, present, and future using powerful card interpretations.', 'Trust your intuition and take positive steps forward.', '2026-03-19 15:32:58', '2026-03-19 15:32:58'),
(2, 'Horoscope Analysis', 'horo_thumb.jpg', 'horo_banner.jpg', 'Daily, weekly and monthly horoscope guidance.', 'We provide detailed horoscope analysis based on your zodiac sign and planetary positions.', 'Use horoscope as a guide, not a rulebook.', '2026-03-19 15:32:58', '2026-03-19 15:32:58'),
(3, 'Numerology Consultation', 'num_thumb.jpg', 'num_banner.jpg', 'Understand your life path using numbers.', 'Numerology reveals hidden meanings behind numbers related to your life and destiny.', 'Numbers can guide but your actions define your future.', '2026-03-19 15:32:58', '2026-03-19 15:32:58'),
(4, 'Love & Relationship Guidance', 'love_thumb.jpg', 'love_banner.jpg', 'Get clarity in your love life and relationships.', 'Our experts help you understand emotional compatibility, relationship challenges, and future possibilities.', 'Healthy communication is the key to every relationship.', '2026-03-19 15:33:58', '2026-03-19 15:33:58'),
(5, 'Career Guidance', 'career_thumb.jpg', 'career_banner.jpg', 'Find the right career path and growth opportunities.', 'We provide insights into your strengths, career direction, and job-related decisions.', 'Your skills and effort shape your career more than destiny.', '2026-03-19 15:33:58', '2026-03-19 15:33:58'),
(6, 'Palm Reading', 'palm_thumb.jpg', 'palm_banner.jpg', 'Discover your life through palm lines.', 'Palmistry reveals information about personality, health, and future based on your hand lines.', 'Your hands reflect your life journey.', '2026-03-19 15:33:58', '2026-03-19 15:33:58'),
(7, 'Vastu Consultation', 'vastu_thumb.jpg', 'vastu_banner.jpg', 'Improve energy flow in your home or office.', 'Vastu helps balance energies in your environment for better health, wealth, and happiness.', 'Positive space creates positive life.', '2026-03-19 15:33:58', '2026-03-19 15:33:58'),
(8, 'Spiritual Healing', 'heal_thumb.jpg', 'heal_banner.jpg', 'Restore balance in mind, body, and soul.', 'Our healing sessions focus on removing negative energy and improving emotional well-being.', 'Inner peace leads to outer success.', '2026-03-19 15:33:58', '2026-03-19 15:33:58'),
(9, 'Marriage Compatibility', 'marriage_thumb.jpg', 'marriage_banner.jpg', 'Check compatibility before marriage.', 'We analyze kundli matching and compatibility factors to ensure a harmonious married life.', 'Compatibility builds a strong foundation for marriage.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(10, 'Health Astrology', 'health_thumb.jpg', 'health_banner.jpg', 'Astrological insights for your health.', 'Understand possible health issues and preventive measures through astrology.', 'Health is wealth—stay aware and proactive.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(11, 'Finance & Wealth Guidance', 'finance_thumb.jpg', 'finance_banner.jpg', 'Improve your financial decisions.', 'Get insights on wealth growth, investments, and financial stability.', 'Smart planning leads to financial freedom.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(12, 'Child & Education Guidance', 'education_thumb.jpg', 'education_banner.jpg', 'Guide your child’s future and education.', 'We provide insights into your child’s strengths and best career/education paths.', 'Right guidance shapes a bright future.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(13, 'Business Consultation', 'business_thumb.jpg', 'business_banner.jpg', 'Grow your business with expert advice.', 'Analyze business opportunities, risks, and growth strategies.', 'Strategy and timing define success.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(14, 'Reiki Healing', 'reiki_thumb.jpg', 'reiki_banner.jpg', 'Energy healing through Reiki techniques.', 'Reiki helps in reducing stress and improving emotional and physical well-being.', 'Healing begins within.', '2026-03-19 15:37:46', '2026-03-19 15:37:46'),
(15, 'Face Reading', 'face_thumb.jpg', 'face_banner.jpg', 'Understand personality through facial features.', 'Face reading reveals character traits and future possibilities based on facial structure.', 'Your face reflects your inner self.', '2026-03-19 15:37:46', '2026-03-19 15:37:46');

